import { NextRequest, NextResponse } from 'next/server';
import { prisma } from '@/lib/db';
import { validateRequestUser } from '@/lib/auth-server';
import { validateItemInput } from '@/lib/validation';
import { broadcastUpdate } from '@/lib/events';

export const dynamic = 'force-dynamic';

// GET /api/items - Fetch all items (active and used)
export async function GET(req: NextRequest) {
  try {
    const items = await prisma.item.findMany({
      include: {
        addedBy: { select: { id: true, name: true } },
        lastTouchedBy: { select: { id: true, name: true } },
        usedUpBy: { select: { id: true, name: true } },
      },
      orderBy: { updatedAt: 'desc' },
    });

    return NextResponse.json(items);
  } catch (error) {
    console.error('GET /api/items error:', error);
    return NextResponse.json(
      { error: 'Failed to retrieve inventory items.' },
      { status: 500 }
    );
  }
}

// POST /api/items - Add a new item
export async function POST(req: NextRequest) {
  try {
    // 1. Authenticate user
    const user = await validateRequestUser(req);
    if (!user) {
      return NextResponse.json(
        { error: 'Unauthorized. Please log in first.' },
        { status: 401 }
      );
    }

    // 2. Parse and validate body
    const body = await req.json().catch(() => ({}));
    const { error, validatedData } = validateItemInput(body);

    if (error || !validatedData) {
      return NextResponse.json({ error }, { status: 400 });
    }

    // 3. Create the item in database
    const item = await prisma.item.create({
      data: {
        name: validatedData.name,
        category: validatedData.category,
        quantityType: validatedData.quantityType,
        quantityValue: validatedData.quantityValue,
        unit: validatedData.unit,
        expiryDate: validatedData.expiryDate ? new Date(validatedData.expiryDate) : null,
        status: 'active',
        addedById: user.id,
        lastTouchedById: user.id,
      },
      include: {
        addedBy: { select: { id: true, name: true } },
        lastTouchedBy: { select: { id: true, name: true } },
        usedUpBy: { select: { id: true, name: true } },
      },
    });

    // 4. Broadcast event in real-time
    broadcastUpdate('create', item);

    return NextResponse.json(item, { status: 201 });
  } catch (error) {
    console.error('POST /api/items error:', error);
    return NextResponse.json(
      { error: 'Failed to create inventory item.' },
      { status: 500 }
    );
  }
}
