import { NextRequest } from 'next/server';
import { prisma } from './db';

/**
 * Validates request headers x-user-id and x-user-token against the SQLite database.
 * Returns the authenticated user object, or null if validation fails.
 */
export async function validateRequestUser(req: NextRequest) {
  const userId = req.headers.get('x-user-id');
  const userToken = req.headers.get('x-user-token');

  if (!userId || !userToken) {
    return null;
  }

  try {
    const user = await prisma.user.findUnique({
      where: { id: userId },
    });

    if (!user || user.token !== userToken) {
      return null;
    }

    return user;
  } catch (e) {
    console.error('[Auth Helper] Error validating user:', e);
    return null;
  }
}
